const results = $.steps.searchProspects.response.results || [];
const maxLeads = parseInt($.input.maxLeads || '10', 10);

const seen = new Set();
const skipDomains = ['yelp.com', 'yellowpages.com', 'facebook.com', 'linkedin.com', 'instagram.com', 'twitter.com', 'google.com', 'tripadvisor.com', 'bbb.org'];

const prospects = results.filter(r => {
  try {
    const hostname = new URL(r.url).hostname.replace('www.', '');
    if (seen.has(hostname)) return false;
    if (skipDomains.some(d => hostname.includes(d))) return false;
    seen.add(hostname);
    return true;
  } catch(e) { return false; }
}).slice(0, maxLeads);

const urls = prospects.map(p => p.url);
const prospectInfo = prospects.map((p, i) => ({ index: i + 1, title: p.title || '', url: p.url, snippet: (p.text || '').slice(0, 200) }));

return { urls, prospectInfo, totalFound: results.length, selectedCount: urls.length };

const prospectInfo = $.steps.filterUrls.output.prospectInfo;
const iterations = $.steps.scrapeProspects.response.iterations || [];
const urls = $.steps.filterUrls.output.urls;

let scrapedData = '';
iterations.forEach((iter, i) => {
  const url = urls[i] || 'Unknown';
  const info = prospectInfo[i] || {};
  const resp = (iter.scrapeSite && iter.scrapeSite.response && iter.scrapeSite.response.data) ? iter.scrapeSite.response.data : {};
  const md = resp.markdown || '';

  scrapedData += '=== PROSPECT ' + (i + 1) + ' ===\n';
  scrapedData += 'URL: ' + url + '\n';
  scrapedData += 'Title: ' + (info.title || '') + '\n';
  scrapedData += 'Snippet: ' + (info.snippet || '') + '\n';
  scrapedData += 'Page content:\n' + md.slice(0, 2000) + '\n\n';
});

return { scrapedData, scrapedCount: iterations.length };

const d = $.steps.compileScrapedData.output;
const industry = $.input.industry;
const location = $.input.location;
const valueProp = $.input.valueProposition;
const sender = $.input.senderName || 'Sales Team';

let prompt = 'You are a B2B sales and lead qualification expert. Analyze the scraped prospect websites, qualify each lead, and compose personalized outreach emails.\n\n';
prompt += 'TARGET INDUSTRY: ' + industry + '\n';
prompt += 'LOCATION: ' + location + '\n';
prompt += 'VALUE PROPOSITION: ' + valueProp + '\n';
prompt += 'SENDER NAME: ' + sender + '\n\n';
prompt += 'SCRAPED PROSPECT DATA:\n' + d.scrapedData + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '1. Extract contact info (emails, phones) from each prospect\n';
prompt += '2. Qualify each lead: A (decision-maker email found, good fit), B (general email, potential fit), C (no email or poor fit)\n';
prompt += '3. For grade A and B leads, compose a personalized outreach email that references their business specifics\n';
prompt += '4. Keep emails 80-150 words, professional, with a clear CTA\n';
prompt += '5. Use HTML formatting with <p> tags for email body\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "leads": [\n';
prompt += '    {\n';
prompt += '      "businessName": "name",\n';
prompt += '      "website": "url",\n';
prompt += '      "email": "contact@example.com",\n';
prompt += '      "phone": "phone or empty",\n';
prompt += '      "leadGrade": "A|B|C",\n';
prompt += '      "qualificationNotes": "why this grade",\n';
prompt += '      "emailSubject": "personalized subject line",\n';
prompt += '      "emailBody": "<p>personalized HTML outreach email</p>",\n';
prompt += '      "personalizationHook": "what was personalized"\n';
prompt += '    }\n';
prompt += '  ],\n';
prompt += '  "summary": { "total": 0, "gradeA": 0, "gradeB": 0, "gradeC": 0, "withEmail": 0 }\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { leads: [], summary: { total: 0, gradeA: 0, gradeB: 0, gradeC: 0, withEmail: 0 }, error: raw }; }

const ai = $.steps.parseAI.output;
const leads = ai.leads || [];
const date = new Date().toISOString().split('T')[0];

const sheetData = leads.map((lead, i) => ({
  '#': i + 1,
  'Business Name': lead.businessName || '',
  'Website': lead.website || '',
  'Email': lead.email || '',
  'Phone': lead.phone || '',
  'Lead Grade': lead.leadGrade || 'C',
  'Qualification Notes': lead.qualificationNotes || '',
  'Email Sent': (lead.leadGrade === 'A' || lead.leadGrade === 'B') && lead.email ? 'Yes' : 'No',
  'Date': date
}));

const emailableLeads = leads.filter(l => (l.leadGrade === 'A' || l.leadGrade === 'B') && l.email && l.emailBody);

return { sheetData, emailableLeads, leadCount: leads.length, summary: ai.summary || {} };

const ai = $.steps.parseAI.output;
const summary = $.steps.buildSheetData.output.summary;
const emailable = $.steps.buildSheetData.output.emailableLeads || [];
const leads = ai.leads || [];

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Lead Generation Complete' } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Industry:*\n' + $.input.industry },
  { type: 'mrkdwn', text: '*Location:*\n' + $.input.location }
] });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Total Leads:*\n' + leads.length },
  { type: 'mrkdwn', text: '*Emails Sent:*\n' + emailable.length }
] });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Grade A:*\n' + (summary.gradeA || 0) },
  { type: 'mrkdwn', text: '*Grade B:*\n' + (summary.gradeB || 0) }
] });
blocks.push({ type: 'divider' });

let leadList = '';
leads.slice(0, 8).forEach((l, i) => {
  const emoji = l.leadGrade === 'A' ? ':star:' : l.leadGrade === 'B' ? ':large_blue_circle:' : ':white_circle:';
  leadList += emoji + ' *' + (l.businessName || 'Unknown') + '* (' + l.leadGrade + ') - ' + (l.email || 'no email') + '\n';
});
if (leads.length > 8) leadList += '... and ' + (leads.length - 8) + ' more';

blocks.push({ type: 'section', text: { type: 'mrkdwn', text: leadList.slice(0, 1800) } });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Exa + Firecrawl + Claude AI + Gmail + Sheets' }] });

const fallback = 'Lead gen complete: ' + leads.length + ' leads found, ' + emailable.length + ' emails sent';
return { blocks, fallback };
